// C# — Binary Search Tree: Insert, Search, Delete, Traversals, FindMin, FindMax, Height, Size

public class BSTNode
{
    public int Data;
    public BSTNode? Left, Right;
    public BSTNode(int data) { Data = data; }
}

public class BinarySearchTree
{
    private BSTNode? root;

    // Insert
    public void Insert(int data) => root = InsertRec(root, data);
    private BSTNode InsertRec(BSTNode? node, int data)
    {
        if (node is null) return new BSTNode(data);
        if (data < node.Data) node.Left = InsertRec(node.Left, data);
        else if (data > node.Data) node.Right = InsertRec(node.Right, data);
        return node; // duplicate values are ignored
    }

    // Search
    public bool Search(int target) => SearchRec(root, target);
    private bool SearchRec(BSTNode? node, int target)
    {
        if (node is null) return false;
        if (target == node.Data) return true;
        return target < node.Data
            ? SearchRec(node.Left, target)
            : SearchRec(node.Right, target);
    }

    // Delete
    public void Delete(int data) => root = DeleteRec(root, data);
    private BSTNode? DeleteRec(BSTNode? node, int data)
    {
        if (node is null) return null;
        if (data < node.Data) node.Left = DeleteRec(node.Left, data);
        else if (data > node.Data) node.Right = DeleteRec(node.Right, data);
        else
        {
            // Case 1: leaf node
            if (node.Left is null && node.Right is null) return null;
            // Case 2: one child
            if (node.Left is null) return node.Right;
            if (node.Right is null) return node.Left;
            // Case 3: two children — replace with inorder successor
            node.Data = FindMinValue(node.Right);
            node.Right = DeleteRec(node.Right, node.Data);
        }
        return node;
    }

    // Inorder — Left, Root, Right (ascending order)
    public void Inorder(BSTNode? node)
    {
        if (node is null) return;
        Inorder(node.Left);
        Console.Write(node.Data + " ");
        Inorder(node.Right);
    }

    // Preorder — Root, Left, Right
    public void Preorder(BSTNode? node)
    {
        if (node is null) return;
        Console.Write(node.Data + " ");
        Preorder(node.Left);
        Preorder(node.Right);
    }

    // Postorder — Left, Right, Root
    public void Postorder(BSTNode? node)
    {
        if (node is null) return;
        Postorder(node.Left);
        Postorder(node.Right);
        Console.Write(node.Data + " ");
    }

    // Find Min — leftmost node
    public int FindMin()
    {
        if (root is null) throw new InvalidOperationException("Tree is empty.");
        return FindMinValue(root);
    }
    private int FindMinValue(BSTNode node)
    {
        while (node.Left is not null) node = node.Left;
        return node.Data;
    }

    // Find Max — rightmost node
    public int FindMax()
    {
        if (root is null) throw new InvalidOperationException("Tree is empty.");
        var node = root;
        while (node.Right is not null) node = node.Right;
        return node.Data;
    }

    // Get Height
    public int GetHeight(BSTNode? node)
    {
        if (node is null) return -1;
        return 1 + Math.Max(GetHeight(node.Left), GetHeight(node.Right));
    }

    // Get Size
    public int GetSize(BSTNode? node)
    {
        if (node is null) return 0;
        return 1 + GetSize(node.Left) + GetSize(node.Right);
    }
}

// Usage
var bst = new BinarySearchTree();
bst.Insert(5); bst.Insert(3); bst.Insert(7);
