// C++ — Binary Search Tree: Insert, Search, Delete, Traversals, FindMin, FindMax, Height, Size
#include <iostream>
using namespace std;

struct BSTNode {
    int data;
    BSTNode *left, *right;
    BSTNode(int d) : data(d), left(nullptr), right(nullptr) {}
};

class BST {
    BSTNode* root = nullptr;

    BSTNode* insertRec(BSTNode* node, int data) {
        if (!node) return new BSTNode(data);
        if (data < node->data) node->left = insertRec(node->left, data);
        else if (data > node->data) node->right = insertRec(node->right, data);
        return node;
    }

    bool searchRec(BSTNode* node, int target) {
        if (!node) return false;
        if (target == node->data) return true;
        return target < node->data ? searchRec(node->left, target) : searchRec(node->right, target);
    }

    int findMinValue(BSTNode* node) {
        while (node->left) node = node->left;
        return node->data;
    }

    BSTNode* deleteRec(BSTNode* node, int data) {
        if (!node) return nullptr;
        if (data < node->data) node->left = deleteRec(node->left, data);
        else if (data > node->data) node->right = deleteRec(node->right, data);
        else {
            if (!node->left && !node->right) { delete node; return nullptr; }
            if (!node->left) { BSTNode* tmp = node->right; delete node; return tmp; }
            if (!node->right) { BSTNode* tmp = node->left; delete node; return tmp; }
            node->data = findMinValue(node->right);
            node->right = deleteRec(node->right, node->data);
        }
        return node;
    }

    void inorderRec(BSTNode* node) {
        if (!node) return;
        inorderRec(node->left);
        cout << node->data << " ";
        inorderRec(node->right);
    }

    void preorderRec(BSTNode* node) {
        if (!node) return;
        cout << node->data << " ";
        preorderRec(node->left);
        preorderRec(node->right);
    }

    void postorderRec(BSTNode* node) {
        if (!node) return;
        postorderRec(node->left);
        postorderRec(node->right);
        cout << node->data << " ";
    }

    int heightRec(BSTNode* node) {
        if (!node) return -1;
        return 1 + max(heightRec(node->left), heightRec(node->right));
    }

    int sizeRec(BSTNode* node) {
        if (!node) return 0;
        return 1 + sizeRec(node->left) + sizeRec(node->right);
    }

public:
    void insert(int data) { root = insertRec(root, data); }
    bool search(int target) { return searchRec(root, target); }
    void deleteNode(int data) { root = deleteRec(root, data); }
    void inorder() { inorderRec(root); }
    void preorder() { preorderRec(root); }
    void postorder() { postorderRec(root); }
    int findMin() { return findMinValue(root); }
    int findMax() {
        BSTNode* node = root;
        while (node->right) node = node->right;
        return node->data;
    }
    int getHeight() { return heightRec(root); }
    int getSize() { return sizeRec(root); }
