// Java — Binary Search Tree: Insert, Search, Delete, Traversals, FindMin, FindMax, Height, Size

class BSTNode {
    int data;
    BSTNode left, right;
    BSTNode(int data) { this.data = data; }
}

public class BinarySearchTree {
    private BSTNode root;

    // Insert
    public void insert(int data) { root = insertRec(root, data); }
    private BSTNode insertRec(BSTNode node, int data) {
        if (node == null) return new BSTNode(data);
        if (data < node.data) node.left = insertRec(node.left, data);
        else if (data > node.data) node.right = insertRec(node.right, data);
        return node;
    }

    // Search
    public boolean search(int target) { return searchRec(root, target); }
    private boolean searchRec(BSTNode node, int target) {
        if (node == null) return false;
        if (target == node.data) return true;
        return target < node.data ? searchRec(node.left, target) : searchRec(node.right, target);
    }

    // Delete
    public void delete(int data) { root = deleteRec(root, data); }
    private BSTNode deleteRec(BSTNode node, int data) {
        if (node == null) return null;
        if (data < node.data) node.left = deleteRec(node.left, data);
        else if (data > node.data) node.right = deleteRec(node.right, data);
        else {
            if (node.left == null && node.right == null) return null;
            if (node.left == null) return node.right;
            if (node.right == null) return node.left;
            node.data = findMinValue(node.right);
            node.right = deleteRec(node.right, node.data);
        }
        return node;
    }

    // Inorder — Left, Root, Right
    public void inorder(BSTNode node) {
        if (node == null) return;
        inorder(node.left);
        System.out.print(node.data + " ");
        inorder(node.right);
    }

    // Preorder — Root, Left, Right
    public void preorder(BSTNode node) {
        if (node == null) return;
        System.out.print(node.data + " ");
        preorder(node.left);
        preorder(node.right);
    }

    // Postorder — Left, Right, Root
    public void postorder(BSTNode node) {
        if (node == null) return;
        postorder(node.left);
        postorder(node.right);
        System.out.print(node.data + " ");
    }

    // Find Min
    public int findMin() { return findMinValue(root); }
    private int findMinValue(BSTNode node) {
        while (node.left != null) node = node.left;
        return node.data;
    }

    // Find Max
    public int findMax() {
        BSTNode node = root;
        while (node.right != null) node = node.right;
        return node.data;
    }

    // Get Height
    public int getHeight(BSTNode node) {
        if (node == null) return -1;
        return 1 + Math.max(getHeight(node.left), getHeight(node.right));
    }

    // Get Size
    public int getSize(BSTNode node) {
        if (node == null) return 0;
        return 1 + getSize(node.left) + getSize(node.right);
    }

    public static void main(String[] args) {
        BinarySearchTree bst = new BinarySearchTree();
        bst.insert(5); bst.insert(3); bst.insert(7);
        bst.insert(1); bst.insert(4); bst.insert(6); bst.insert(8);
        bst.inorder(bst.root);   // 1 3 4 5 6 7 8
        bst.delete(3);
        boolean found = bst.search(4); // true
        int min = bst.findMin();       // 1
        int max = bst.findMax();       // 8
    }
}

// JavaScript — Binary Search Tree: Insert, Search, Delete, Traversals, FindMin, FindMax, Height, Size

class BSTNode {
    constructor(data) {
        this.data = data;
        this.left = null;
        this.right = null;
    }
}

class BinarySearchTree {
    constructor() { this.root = null; }

    // Insert
    insert(data) { this.root = this._insertRec(this.root, data); }
    _insertRec(node, data) {
        if (!node) return new BSTNode(data);
        if (data < node.data) node.left = this._insertRec(node.left, data);
        else if (data > node.data) node.right = this._insertRec(node.right, data);
        return node;
    }

    // Search
    search(target) { return this._searchRec(this.root, target); }
    _searchRec(node, target) {
        if (!node) return false;
        if (target === node.data) return true;
        return target < node.data
            ? this._searchRec(node.left, target)
            : this._searchRec(node.right, target);
    }

    // Delete
    delete(data) { this.root = this._deleteRec(this.root, data); }
    _deleteRec(node, data) {
        if (!node) return null;
        if (data < node.data) node.left = this._deleteRec(node.left, data);
        else if (data > node.data) node.right = this._deleteRec(node.right, data);
        else {
            if (!node.left && !node.right) return null;
            if (!node.left) return node.right;
            if (!node.right) return node.left;
            node.data = this._findMinValue(node.right);
            node.right = this._deleteRec(node.right, node.data);
        }
        return node;
    }

    // Inorder — Left, Root, Right
    inorder(node = this.root) {
        if (!node) return;
        this.inorder(node.left);
        process.stdout.write(node.data + ' ');
        this.inorder(node.right);
    }

    // Preorder — Root, Left, Right
    preorder(node = this.root) {
        if (!node) return;
        process.stdout.write(node.data + ' ');
        this.preorder(node.left);
        this.preorder(node.right);
    }

    // Postorder — Left, Right, Root
    postorder(node = this.root) {
        if (!node) return;
        this.postorder(node.left);
        this.postorder(node.right);
        process.stdout.write(node.data + ' ');
    }

    // Find Min
    findMin() {
        return this._findMinValue(this.root);
    }
    _findMinValue(node) {
        while (node.left) node = node.left;
        return node.data;
    }

    // Find Max
    findMax() {
        let node = this.root;
        while (node.right) node = node.right;
        return node.data;
    }

    // Get Height
    getHeight(node = this.root) {
        if (!node) return -1;
        return 1 + Math.max(this.getHeight(node.left), this.getHeight(node.right));
    }

    // Get Size
    getSize(node = this.root) {
        if (!node) return 0;
        return 1 + this.getSize(node.left) + this.getSize(node.right);
    }
}

